export type Cell = [number, number];

function countNeighbors(cell: Cell, livingCells: Cell[]): number {
  return livingCells.filter(
    (other) =>
      !(other[0] === cell[0] && other[1] === cell[1]) &&
      Math.abs(other[0] - cell[0]) <= 1 &&
      Math.abs(other[1] - cell[1]) <= 1
  ).length;
}

export function nextGeneration(livingCells: Cell[]): Cell[] {
  const survivors = livingCells.filter((cell) => {
    const neighborCount = countNeighbors(cell, livingCells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const deadCandidates = new Map<string, Cell>();
  for (const cell of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [cell[0] + dx, cell[1] + dy];
        const key = `${neighbor[0]},${neighbor[1]}`;
        if (!livingCells.some((c) => c[0] === neighbor[0] && c[1] === neighbor[1])) {
          deadCandidates.set(key, neighbor);
        }
      }
    }
  }

  const births: Cell[] = [];
  for (const [, candidate] of deadCandidates) {
    if (countNeighbors(candidate, livingCells) === 3) {
      births.push(candidate);
    }
  }

  return [...survivors, ...births];
}
```

Review for refactoring. Possible improvements:
- The `livingCells.some(...)` check for dead cells duplicates the neighbor-checking pattern. Consider using a Set for O(1) lookup.
- The `countNeighbors` function checks `!(other[0] === cell[0] && other[1] === cell[1])` — for dead cells this check is always true since the candidate is never in livingCells. But it's harmless.
- Consider extracting the dead-candidate-finding logic into a helper.

Keep it simple — only refactor if it genuinely improves clarity. Ensure all tests pass.

